-- Generated at 2026-04-02T16:57:19.322Z
-- Applies SR.csv Combined as approved English glosses for NT words.

begin;

do $$
begin
  if not exists (select 1 from language where code = 'eng') then
    raise exception 'Language code eng was not found';
  end if;
end $$;

create temp table _sr_word_gloss (
  word_id text primary key,
  gloss text not null
) on commit drop;











































































































































-- delete multi word phrases
with multi_phrase as (
    select p.id as phrase_id
    from phrase as p
    join phrase_word as pw on pw.phrase_id = p.id
    join word as w on w.id = pw.word_id
    join verse as v on v.id = w.verse_id
    where p.deleted_at is null and v.book_id >= 40
    and p.language_id = (select id from language where code = 'eng')
    group by p.id
    having count(*) > 1
)
update phrase as p
set deleted_at = now(), deleted_by = null
where p.id in (select phrase_id from multi_phrase);

create temp table _nt_words on commit drop as
select w.id as word_id
from word as w
join verse as v on v.id = w.verse_id
where v.book_id >= 40;


create temp table _missing_words on commit drop as
with eng as (select id from language where code = 'eng' limit 1)
select nw.word_id
from _nt_words as nw
left join (
  select pw.word_id
  from phrase as p
  join eng on p.language_id = eng.id
  join phrase_word as pw on pw.phrase_id = p.id
  where p.deleted_at is null
) as existing on existing.word_id = nw.word_id
where existing.word_id is null;

-- insert missing phrases
with new_phrase_map as (
    select mw.word_id, nextval('phrase_id_seq')::int as phrase_id
    from _missing_words as mw
    order by mw.word_id
),
new_phrase as (
    select npm.phrase_id, eng.id, now(), null, null, null
    from new_phrase_map as npm
    cross join (select id from language where code = 'eng' limit 1) as eng
)
select phrase_id, word_id
from new_phrase_map;

create temp table _target_phrase_word on commit drop as
select pw.word_id, p.id as phrase_id
from phrase as p
join phrase_word as pw on pw.phrase_id = p.id
join word as w on w.id = pw.word_id
join verse as v on v.id = w.verse_id
where p.deleted_at is null and v.book_id >= 40
and p.language_id = (select id from language where code = 'eng');

do $$
begin
  if exists (
    select 1
    from _target_phrase_word
    group by word_id
    having count(*) <> 1
  ) then
    raise exception 'Expected exactly one active English phrase per NT word after splitting';
  end if;

  if (select count(*) from _target_phrase_word) <> (select count(*) from _sr_word_gloss) then
    raise exception 'Target phrase-word row count (%) does not match SR word-gloss row count (%)',
      (select count(*) from _target_phrase_word), (select count(*) from _sr_word_gloss);
  end if;
end $$;

select setval('gloss_history_id_seq', coalesce((select max(id) from gloss_history), 0) + 1, false);
select setval('lemma_form_suggestion_id_seq', coalesce((select max(id) from lemma_form_suggestion), 0) + 1, false);

select tpw.phrase_id, swg.gloss, 'APPROVED', 'IMPORT', now(), null
from _sr_word_gloss as swg
join _target_phrase_word as tpw on tpw.word_id = swg.word_id
on conflict (phrase_id) do update
set
  gloss = excluded.gloss,
  state = 'APPROVED',
  source = 'IMPORT',
  updated_at = excluded.updated_at,
  updated_by = null;

commit;
